void FCM_RefreshRegisterArrayFromVariables()
{

  // Copy identity, status and PWM values into register array
  FCV_REGISTERS[0] = FCV_REGPROTOCOLVERSION;
  FCV_REGISTERS[1] = FCV_REGFIRMWAREMAJOR;
  FCV_REGISTERS[2] = FCV_REGFIRMWAREMINOR;
  FCV_REGISTERS[3] = FCV_REGTOOLTYPEID;
  FCV_REGISTERS[4] = FCV_REGSTATUSFLAGS;
  FCV_REGISTERS[5] = FCV_REGPWM1DUTY;
  FCV_REGISTERS[6] = FCV_REGPWM2DUTY;
  FCV_REGISTERS[7] = FCV_REGPWMCONTROL;

  // Copy current measurement bytes into register array
  FCV_REGISTERS[11] = FCV_REGCURRENT1MA_L;
  FCV_REGISTERS[12] = FCV_REGCURRENT1MA_H;
  FCV_REGISTERS[13] = FCV_REGCURRENT2MA_L;
  FCV_REGISTERS[14] = FCV_REGCURRENT2MA_H;

  // Copy ADC telemetry bytes into register array
  FCV_REGISTERS[15] = FCV_REGADC0RAW_L;
  FCV_REGISTERS[16] = FCV_REGADC0RAW_H;
  FCV_REGISTERS[17] = FCV_REGADC1RAW_L;
  FCV_REGISTERS[18] = FCV_REGADC1RAW_H;
  FCV_REGISTERS[19] = FCV_REGADC0MV_L;
  FCV_REGISTERS[20] = FCV_REGADC0MV_H;
  FCV_REGISTERS[21] = FCV_REGADC1MV_L;
  FCV_REGISTERS[22] = FCV_REGADC1MV_H;

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_UpdateAdcTelemetry()
{

  //Comment:
  //Refresh local ADC telemetry values each loop

  // Decision
  if (FCV_ADCCHANNEL & 0x01)
  {  

    // Read ADC1 raw value (0-4095)
    FCV_ADC1RAW = FCD_07042_ADC1__GetInt();

    // Clamp ADC1 raw to max count
    if (FCV_ADC1RAW > FCV_ADCMAXCOUNTS)
    {    

      // Force ADC1 raw into valid range
      FCV_ADC1RAW = FCV_ADCMAXCOUNTS;

    // } else {

    }

    // Convert raw counts to millivolts using configured reference
    FCV_ADC1MV = FCV_ADC1RAW * FCV_ADCREFERENCEMV / FCV_ADCMAXCOUNTS;

    // Store ADC telemetry in low/high byte registers
    FCV_REGADC1RAW_L = FCV_ADC1RAW & 255;
    FCV_REGADC1RAW_H = FCV_ADC1RAW >> 8;
    FCV_REGADC1MV_L = FCV_ADC1MV & 255;
    FCV_REGADC1MV_H = FCV_ADC1MV >> 8;

  } else {

    // Read ADC0 raw value (0-4095)
    FCV_ADC0RAW = FCD_07041_ADC0__GetInt();

    // Clamp ADC0 raw to max count
    if (FCV_ADC0RAW > FCV_ADCMAXCOUNTS)
    {    

      // Force ADC0 raw into valid range
      FCV_ADC0RAW = FCV_ADCMAXCOUNTS;

    // } else {

    }

    // Convert raw counts to millivolts using configured reference
    FCV_ADC0MV = FCV_ADC0RAW * FCV_ADCREFERENCEMV / FCV_ADCMAXCOUNTS;

    // Store ADC telemetry in low/high byte registers
    FCV_REGADC0RAW_L = FCV_ADC0RAW & 255;
    FCV_REGADC0RAW_H = FCV_ADC0RAW >> 8;
    FCV_REGADC0MV_L = FCV_ADC0MV & 255;
    FCV_REGADC0MV_H = FCV_ADC0MV >> 8;

  }

  // Move to next channel
  FCV_ADCCHANNEL = FCV_ADCCHANNEL + 1;

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_ProcessCommsByte()
{
  //Local variable definitions
  MX_UINT8 FCL_RX = (0x0);


  // Get next received byte from circular buffer
  FCL_RX = FCD_01211_CircularBuffer1__GetByte();

  // Parser state 0: wait for header byte 1 (0xFF)
  if (FCV_PARSERSTATE == 0)
  {  

    // Byte equals header value
    if (FCL_RX == FCV_STS_HEADER)
    {    

      // Move to parser state 1 (wait for second header byte)
      FCV_PARSERSTATE = 1;

    // } else {

    }

  } else {

    // Parser state 1: wait for header byte 2 (0xFF)
    if (FCV_PARSERSTATE == 1)
    {    

      // Second header matched
      if (FCL_RX == FCV_STS_HEADER)
      {      

        // Move to parser state 2 (read packet ID)
        FCV_PARSERSTATE = 2;

      } else {

        // Header mismatch: reset parser (or restart if new header)
        FCV_PARSERSTATE = 0;

        // If this byte is 0xFF, treat as possible first header
        if (FCL_RX == FCV_STS_HEADER)
        {        

          // Restart at state 1
          FCV_PARSERSTATE = 1;

        // } else {

        }

      }

    } else {

      // Parser state 2: read packet ID
      if (FCV_PARSERSTATE == 2)
      {      

        // Store packet ID and start checksum sum
        FCV_PACKETID = FCL_RX;
        FCV_PACKETCHECKSUMCALC = FCL_RX;
        FCV_PARSERSTATE = 3;

      } else {

        // Parser state 3: read packet LENGTH
        if (FCV_PARSERSTATE == 3)
        {        

          // Store LENGTH and compute expected parameter count
          FCV_PACKETLENGTH = FCL_RX;
          FCV_PACKETCHECKSUMCALC = FCV_PACKETCHECKSUMCALC + FCL_RX;
          FCV_PACKETPARAMCOUNT = FCV_PACKETLENGTH - 2;
          FCV_PACKETPARAMINDEX = 0;
          FCV_PARSERSTATE = 4;

        } else {

          // Parser state 4: read instruction byte
          if (FCV_PARSERSTATE == 4)
          {          

            // Store instruction and update checksum sum
            FCV_PACKETINSTRUCTION = FCL_RX;
            FCV_PACKETCHECKSUMCALC = FCV_PACKETCHECKSUMCALC + FCL_RX;

            // If there are parameters, move to state 5, else read checksum in state 6
            if (FCV_PACKETPARAMCOUNT > 0)
            {            

              // Go to parameter parsing state
              FCV_PARSERSTATE = 5;

            } else {

              // No parameters, go to checksum state
              FCV_PARSERSTATE = 6;

            }

          } else {

            // Parser state 5: read parameter bytes
            if (FCV_PARSERSTATE == 5)
            {            

              // Protect parameter buffer against overflow
              if (FCV_PACKETPARAMINDEX < 32)
              {              

                // Store parameter byte
                FCV_PACKETBUFFER[FCV_PACKETPARAMINDEX] = FCL_RX;

              // } else {

              }

              // Update checksum and parameter index
              FCV_PACKETCHECKSUMCALC = FCV_PACKETCHECKSUMCALC + FCL_RX;
              FCV_PACKETPARAMINDEX = FCV_PACKETPARAMINDEX + 1;

              // All parameters received
              if (FCV_PACKETPARAMINDEX >= FCV_PACKETPARAMCOUNT)
              {              

                // Move to checksum state
                FCV_PARSERSTATE = 6;

              // } else {

              }

            } else {

              // Parser state 6: read and validate checksum
              if (FCV_PARSERSTATE == 6)
              {              

                // Store received checksum
                FCV_PACKETCHECKSUMRX = FCL_RX;

                // Calculate expected checksum (~sum & 0xFF)
                FCV_PACKETCHECKSUMCALC = ~FCV_PACKETCHECKSUMCALC;
                FCV_PACKETCHECKSUMCALC = FCV_PACKETCHECKSUMCALC & 255;

                // Valid checksum and packet addressed to this node
                if ((FCV_PACKETCHECKSUMRX == FCV_PACKETCHECKSUMCALC) && (FCV_PACKETID == FCV_BUSDEVICEID))
                {                

                  // Track valid packet and basic decoded fields
                  FCV_PACKETVALIDCOUNT = FCV_PACKETVALIDCOUNT + 1;
                  FCV_LASTINSTRUCTION = FCV_PACKETINSTRUCTION;

                  // Handle READ instruction (2)
                  if ((FCV_PACKETINSTRUCTION == 2) && (FCV_PACKETPARAMCOUNT >= 2))
                  {                  

                    // Store READ address and requested length
                    FCV_LASTADDRESS = FCV_PACKETBUFFER[0];
                    FCV_LASTDATALENGTH = FCV_PACKETBUFFER[1];

                    // Verbose debug READ command
                    if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 2))
                    {                    

                      // Debug READ prefix
                      FCD_047b2_UART_ProgDebug__SendString("DBG cmd READ addr=", 19);

                      // Debug READ address
                      FCD_047b2_UART_ProgDebug__SendNumber(FCV_LASTADDRESS);

                      // Debug READ len prefix
                      FCD_047b2_UART_ProgDebug__SendString(" len=", 6);

                      // Debug READ length
                      FCD_047b2_UART_ProgDebug__SendNumber(FCV_LASTDATALENGTH);

                      // Debug line ending
                      FCD_047b2_UART_ProgDebug__SendString("\r\n", 3);

                    // } else {

                    }

                    // Only basic 1-byte READ is supported in first version
                    if (FCV_LASTDATALENGTH == 1)
                    {                    

                      // Map address to a register byte
                      FCM_ReadRegisterIntoReadValue();

                      // Send READ status packet with one data byte
                      FCV_TXLENGTH = 3;
                      FCV_TXERROR = 0;
                      FCV_TXCHECKSUMSUM = FCV_BUSDEVICEID + FCV_TXLENGTH + FCV_TXERROR + FCV_READVALUE;
                      FCV_TXCHECKSUMSUM = ~FCV_TXCHECKSUMSUM;
                      FCV_TXCHECKSUMSUM = FCV_TXCHECKSUMSUM & 255;

                      // Set helper TX data byte from read value
                      FCV_TXDATABYTE = FCV_READVALUE;

                      // Send status packet with one data byte
                      FCM_SendStatusPacketWithData();

                    } else {

                      // Unsupported READ length: send error status packet
                      FCV_TXLENGTH = 2;
                      FCV_TXERROR = 2;
                      FCV_TXCHECKSUMSUM = FCV_BUSDEVICEID + FCV_TXLENGTH + FCV_TXERROR;
                      FCV_TXCHECKSUMSUM = ~FCV_TXCHECKSUMSUM;
                      FCV_TXCHECKSUMSUM = FCV_TXCHECKSUMSUM & 255;

                      // Send status packet without data byte
                      FCM_SendStatusPacketNoData();

                    }

                  } else {

                    // Handle WRITE instruction (3)
                    if ((FCV_PACKETINSTRUCTION == 3) && (FCV_PACKETPARAMCOUNT >= 1))
                    {                    

                      // Store WRITE address and data length
                      FCV_LASTADDRESS = FCV_PACKETBUFFER[0];
                      FCV_LASTDATALENGTH = FCV_PACKETPARAMCOUNT - 1;

                      // Verbose debug WRITE command
                      if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 2))
                      {                      

                        // Debug WRITE prefix
                        FCD_047b2_UART_ProgDebug__SendString("DBG cmd WRITE addr=", 20);

                        // Debug WRITE address
                        FCD_047b2_UART_ProgDebug__SendNumber(FCV_LASTADDRESS);

                        // Debug WRITE len prefix
                        FCD_047b2_UART_ProgDebug__SendString(" len=", 6);

                        // Debug WRITE length
                        FCD_047b2_UART_ProgDebug__SendNumber(FCV_LASTDATALENGTH);

                        // Debug line ending
                        FCD_047b2_UART_ProgDebug__SendString("\r\n", 3);

                      // } else {

                      }

                      // WRITE needs at least one data byte in this basic version
                      if (FCV_PACKETPARAMCOUNT >= 2)
                      {                      

                        // Only registers 3 to 7 are writable
                        if ((FCV_LASTADDRESS >= 3) && (FCV_LASTADDRESS <= 7))
                        {                        

                          // Write byte into register array
                          FCV_REGISTERS[FCV_LASTADDRESS] = FCV_PACKETBUFFER[1];

                          // Apply writable register values to variables and hardware
                          FCM_ApplyWritableRegistersToVariablesAndHardware();

                          // Verbose debug WRITE applied values
                          if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 2))
                          {                          

                            // Debug WRITE applied prefix
                            FCD_047b2_UART_ProgDebug__SendString("DBG write applied pwm1=", 24);

                            // Debug PWM1 duty value
                            FCD_047b2_UART_ProgDebug__SendNumber(FCV_REGPWM1DUTY);

                            // Debug PWM2 prefix
                            FCD_047b2_UART_ProgDebug__SendString(" pwm2=", 7);

                            // Debug PWM2 duty value
                            FCD_047b2_UART_ProgDebug__SendNumber(FCV_REGPWM2DUTY);

                            // Debug control prefix
                            FCD_047b2_UART_ProgDebug__SendString(" ctrl=", 7);

                            // Debug PWM control value
                            FCD_047b2_UART_ProgDebug__SendNumber(FCV_REGPWMCONTROL);

                            // Debug line ending
                            FCD_047b2_UART_ProgDebug__SendString("\r\n", 3);

                          // } else {

                          }

                        // } else {

                        }

                        // Send WRITE acknowledge status packet
                        FCV_TXLENGTH = 2;
                        FCV_TXERROR = 0;
                        FCV_TXCHECKSUMSUM = FCV_BUSDEVICEID + FCV_TXLENGTH + FCV_TXERROR;
                        FCV_TXCHECKSUMSUM = ~FCV_TXCHECKSUMSUM;
                        FCV_TXCHECKSUMSUM = FCV_TXCHECKSUMSUM & 255;

                      } else {

                        // WRITE missing data: send error status packet
                        FCV_TXLENGTH = 2;
                        FCV_TXERROR = 2;
                        FCV_TXCHECKSUMSUM = FCV_BUSDEVICEID + FCV_TXLENGTH + FCV_TXERROR;
                        FCV_TXCHECKSUMSUM = ~FCV_TXCHECKSUMSUM;
                        FCV_TXCHECKSUMSUM = FCV_TXCHECKSUMSUM & 255;

                      }

                    } else {

                      // Handle PING instruction (1)
                      if (FCV_PACKETINSTRUCTION == 1)
                      {                      

                        // PING has no address/data fields and sends status response
                        FCV_LASTADDRESS = 0;
                        FCV_LASTDATALENGTH = 0;
                        FCV_TXLENGTH = 2;
                        FCV_TXERROR = 0;
                        FCV_TXCHECKSUMSUM = FCV_BUSDEVICEID + FCV_TXLENGTH + FCV_TXERROR;
                        FCV_TXCHECKSUMSUM = ~FCV_TXCHECKSUMSUM;
                        FCV_TXCHECKSUMSUM = FCV_TXCHECKSUMSUM & 255;

                        // Verbose debug PING command
                        if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 2))
                        {                        

                          // Debug PING message
                          FCD_047b2_UART_ProgDebug__SendString("DBG cmd PING\r\n", 15);

                        // } else {

                        }

                      } else {

                        // Unsupported instruction: send error status packet
                        FCV_TXLENGTH = 2;
                        FCV_TXERROR = 2;
                        FCV_TXCHECKSUMSUM = FCV_BUSDEVICEID + FCV_TXLENGTH + FCV_TXERROR;
                        FCV_TXCHECKSUMSUM = ~FCV_TXCHECKSUMSUM;
                        FCV_TXCHECKSUMSUM = FCV_TXCHECKSUMSUM & 255;

                        // Verbose debug unknown command
                        if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 2))
                        {                        

                          // Debug unknown prefix
                          FCD_047b2_UART_ProgDebug__SendString("DBG cmd UNKNOWN inst=", 22);

                          // Debug unknown instruction value
                          FCD_047b2_UART_ProgDebug__SendNumber(FCV_PACKETINSTRUCTION);

                          // Debug line ending
                          FCD_047b2_UART_ProgDebug__SendString("\r\n", 3);

                        // } else {

                        }

                      }

                    }

                    // Send status packet without data byte
                    FCM_SendStatusPacketNoData();

                  }

                } else {

                  // Invalid packet for this node or checksum mismatch
                  FCV_PACKETERRORCOUNT = FCV_PACKETERRORCOUNT + 1;

                  // Debug invalid packet notice enabled
                  if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 1))
                  {                  

                    // Debug invalid packet message
                    FCD_047b2_UART_ProgDebug__SendString("DBG invalid packet\r\n", 21);

                  // } else {

                  }

                }

                // Reset parser for next packet
                FCV_PARSERSTATE = 0;

              // } else {

              }

            }

          }

        }

      }

    }

  }

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_UpdateCurrentMeasurements()
{

  //Comment:
  //Refresh ADS1220 current measurements each loop

  // Decision
  if (FCV_CURRENTCHANNEL & 1)
  {  

    // Read PWM2 shunt voltage (AN0 single ended)
    FCV_SHUNT2VOLTS = FCD_0ff31_ADS1220__SampleSglVolts(1, FCV_ADCGAINSETTING);

    // Convert shunt volts to current in amps (I=V/R)
    FCV_CURRENT2A = flt_div(FCV_SHUNT2VOLTS, FCV_SHUNTRESISTANCEOHMS);
    FCV_CURRENT2A = flt_mul(FCV_CURRENT2A, FCV_CURRENTCALIBRATIONGAIN);

    // Clamp PWM2 current lower bound to 0A
    if (flt_lt(FCV_CURRENT2A, 0))
    {    

      // Set PWM2 current to 0A if negative
      FCV_CURRENT2A = 0;

    // } else {

    }

    // Convert amps to milliamps
    FCV_CURRENT2MA = flt_toi(flt_mul(FCV_CURRENT2A, 1000));

    // Clamp PWM2 current upper bound to 2000mA (2A)
    if (FCV_CURRENT2MA > 2000)
    {    

      // Set PWM2 current to 2000mA if above range
      FCV_CURRENT2MA = 2000;

    // } else {

    }

    // Store milliamps in low/high byte register pairs
    FCV_REGCURRENT2MA_L = FCV_CURRENT2MA & 255;
    FCV_REGCURRENT2MA_H = FCV_CURRENT2MA >> 8;

  } else {

    // Read PWM1 shunt voltage (AN0 single ended)
    FCV_SHUNT1VOLTS = flt_fromi(FCD_0ff31_ADS1220__SampleSglRaw(0, FCV_ADCGAINSETTING));

    // Convert shunt volts to current in amps (I=V/R)
    FCV_CURRENT1A = flt_div(FCV_SHUNT1VOLTS, FCV_SHUNTRESISTANCEOHMS);
    FCV_CURRENT1A = flt_mul(FCV_CURRENT1A, FCV_CURRENTCALIBRATIONGAIN);

    // Clamp PWM1 current lower bound to 0A
    if (flt_lt(FCV_CURRENT1A, 0))
    {    

      // Set PWM1 current to 0A if negative
      FCV_CURRENT1A = 0;

    // } else {

    }

    // Convert amps to milliamps
    FCV_CURRENT1MA = flt_toi(flt_mul(FCV_CURRENT1A, 1000));

    // Clamp PWM1 current upper bound to 2000mA (2A)
    if (FCV_CURRENT1MA > 2000)
    {    

      // Set PWM1 current to 2000mA if above range
      FCV_CURRENT1MA = 2000;

    // } else {

    }

    // Store milliamps in low/high byte register pairs
    FCV_REGCURRENT1MA_L = FCV_CURRENT1MA & 255;
    FCV_REGCURRENT1MA_H = FCV_CURRENT1MA >> 8;

  }

  // Move to next channel
  FCV_CURRENTCHANNEL = FCV_CURRENTCHANNEL + 1;

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_ServoBus_RX()
{
  //Local variable definitions
  MX_UINT8 FCL_RX = (0x0);


  // Read byte from Serial servo bus
  FCL_RX = FCD_047b1_UART_ServoBus__ReceiveChar(0);

  // Add byte to circular buffer for processing
  FCD_01211_CircularBuffer1__PutByte(FCL_RX);

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_SendStatusPacketNoData()
{

  // TX Header 1
  FCD_047b1_UART_ServoBus__SendChar(255);

  // TX Header 2
  FCD_047b1_UART_ServoBus__SendChar(255);

  // TX ID
  FCD_047b1_UART_ServoBus__SendChar(FCV_BUSDEVICEID);

  // TX LENGTH
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXLENGTH);

  // TX ERROR
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXERROR);

  // TX CHECKSUM
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXCHECKSUMSUM);

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_SendStatusPacketWithData()
{

  // TX Header 1
  FCD_047b1_UART_ServoBus__SendChar(255);

  // TX Header 2
  FCD_047b1_UART_ServoBus__SendChar(255);

  // TX ID
  FCD_047b1_UART_ServoBus__SendChar(FCV_BUSDEVICEID);

  // TX LENGTH
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXLENGTH);

  // TX ERROR
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXERROR);

  // TX DATA BYTE
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXDATABYTE);

  // TX CHECKSUM
  FCD_047b1_UART_ServoBus__SendChar(FCV_TXCHECKSUMSUM);

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_ApplyWritableRegistersToVariablesAndHardware()
{

  // Apply writable register bytes to named variables
  FCV_REGTOOLTYPEID = FCV_REGISTERS[3];
  FCV_REGSTATUSFLAGS = FCV_REGISTERS[4];
  FCV_REGPWM1DUTY = FCV_REGISTERS[5];
  FCV_REGPWM2DUTY = FCV_REGISTERS[6];
  FCV_REGPWMCONTROL = FCV_REGISTERS[7];

  //Comment:
  //Apply PWM1 register values to hardware output

  // PWM1 enabled bit is set
  if ((FCV_REGPWMCONTROL & 1) > 0)
  {  

    // Enable PWM1 output
    FCD_0df41_PWM1__Enable();

    // Apply PWM1 duty cycle
    FCD_0df41_PWM1__SetDutyCycle(FCV_REGPWM1DUTY);

  } else {

    // Disable PWM1 output
    FCD_0df41_PWM1__Disable();

  }

  //Comment:
  //Apply PWM2 register values to hardware output

  // PWM2 enabled bit is set
  if ((FCV_REGPWMCONTROL & 2) > 0)
  {  

    // Enable PWM2 output
    FCD_0df42_PWM2__Enable();

    // Apply PWM2 duty cycle
    FCD_0df42_PWM2__SetDutyCycle(FCV_REGPWM2DUTY);

  } else {

    // Disable PWM2 output
    FCD_0df42_PWM2__Disable();

  }

}

/*=----------------------------------------------------------------------=*\
   Use :
\*=----------------------------------------------------------------------=*/
void FCM_ReadRegisterIntoReadValue()
{

  // Read address is inside register array range
  if (FCV_LASTADDRESS < 32)
  {  

    // Read byte directly from register array
    FCV_READVALUE = FCV_REGISTERS[FCV_LASTADDRESS];

  } else {

    // Out-of-range addresses return zero
    FCV_READVALUE = 0;

  }

}



/*========================================================================*\
   Use :Main
\*========================================================================*/
void app_main()
{
    // Initialize NVS
    esp_err_t ret = nvs_flash_init();
    if (ret == ESP_ERR_NVS_NO_FREE_PAGES || ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK( ret );
	ESP_ERROR_CHECK(esp_event_loop_create_default());


  // Component Macro
  FCD_047b1_UART_ServoBus__Initialise();

  // Component Macro
  FCD_047b2_UART_ProgDebug__Initialise();

  // Component Macro
  FCD_0ff31_ADS1220__Initialise();

  // Component Macro
  FCD_0dd21_Servo_Controller1__Initialise();

  // Debug enabled at startup
  if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 1))
  {  

    // Debug boot banner
    FCD_047b2_UART_ProgDebug__SendString("DBG boot\r\n", 11);

  // } else {

  }

  //Comment:
  //Start with PWM outputs disabled and duty set to 0

  // Set PWM1 duty to initial register value
  FCD_0df41_PWM1__SetDutyCycle(FCV_REGPWM1DUTY);

  // Set PWM2 duty to initial register value
  FCD_0df42_PWM2__SetDutyCycle(FCV_REGPWM2DUTY);

  // Disable PWM1 at startup
  FCD_0df41_PWM1__Disable();

  // Disable PWM2 at startup
  FCD_0df42_PWM2__Disable();

  // Interrupt on Servo Bus Enable
  uart1_interrupt_enabled = 1;

  //Comment:
  //Main program loop

  // Loop
  while (1)
  {
    // Decision
    if (FCV_LOOPCOUNTER == 5)
    {    

      // Update ADS1220-based current registers
      FCM_UpdateCurrentMeasurements();

    // } else {

    }

    // Decision
    if (FCV_LOOPCOUNTER == 10)
    {    

      // Update ADC0/ADC1 telemetry registers
      FCM_UpdateAdcTelemetry();

      // Calculation
      FCV_LOOPCOUNTER = 0;

    } else {

      // Calculation
      FCV_LOOPCOUNTER++;

    }

    // Refresh register array from named variables
    FCM_RefreshRegisterArrayFromVariables();

    // Debug periodic status output enabled
    if ((FCV_DEBUGENABLED == 1) && (FCV_DEBUGLEVEL >= 1))
    {    

      // Increment debug counter
      FCV_DEBUGCOUNTER++;

      // Every 100 loops send system status
      if (FCV_DEBUGCOUNTER >= 100)
      {      

        // Reset debug counter
        FCV_DEBUGCOUNTER = 0;

        // Debug status prefix
        FCD_047b2_UART_ProgDebug__SendString("DBG ok valid=", 14);

        // Debug valid packet count
        FCD_047b2_UART_ProgDebug__SendNumber(FCV_PACKETVALIDCOUNT);

        // Debug error separator
        FCD_047b2_UART_ProgDebug__SendString(" err=", 6);

        // Debug error count
        FCD_047b2_UART_ProgDebug__SendNumber(FCV_PACKETERRORCOUNT);

        // Debug line ending
        FCD_047b2_UART_ProgDebug__SendString("\r\n", 3);

      // } else {

      }

    // } else {

    }

    // Process all bytes currently waiting in circular buffer
    while (FCD_01211_CircularBuffer1__GetNumberBytes() > 0)
    {
      // User Macro
      FCM_ProcessCommsByte();

    }

    // Delay to keep watchdog timer happy
    FCI_DELAYBYTE_MS(10);

  }

	mainendloop: goto mainendloop;
}



